import httpx, hashlib
from datetime import datetime
from pathlib import Path

CACHE_DIR = Path("/var/compliance/subprocessor-monitor")

def hash_page(content: str) -> str:
    return hashlib.sha256(content.encode()).hexdigest()

def check_subprocessor_page(vendor: str, url: str) -> dict | None:
    """Fetch vendor sub-processor page and detect changes."""
    cache_file = CACHE_DIR / f"{vendor}.hash"
    r = httpx.get(url, timeout=30)
    r.raise_for_status()
    current_hash = hash_page(r.text)

    if cache_file.exists():
        previous_hash = cache_file.read_text().strip()
        if current_hash != previous_hash:
            cache_file.write_text(current_hash)
            return {
                "vendor": vendor,
                "url": url,
                "changed_at": datetime.utcnow().isoformat(),
                "action": "Trigger subprocessor review workflow",
            }
    else:
        CACHE_DIR.mkdir(parents=True, exist_ok=True)
        cache_file.write_text(current_hash)

    return None  # No change detected

# Run nightly via cron
vendors = {
    "openai": "https://openai.com/policies/sub-processors",
    "anthropic": "https://www.anthropic.com/legal/subprocessors",
}
for vendor, url in vendors.items():
    change = check_subprocessor_page(vendor, url)
    if change:
        print(f"ALERT: {change}")
        # → post to Slack alert channel and open review ticket
